import React from 'react';

// Minimal, clean header: App name on the left, Logout button on the right
const Navbar = ({ user, onLogout }) => {
  return (
    <nav
      className="fixed top-0 left-0 right-0 z-50 bg-white/90 backdrop-blur-lg border-b border-gray-200"
      style={{ boxShadow: '0 4px 20px rgba(0,0,0,0.06)' }}
      role="navigation"
      aria-label="Top navigation"
    >
      {/* Full-width row with no side padding so elements sit at the extreme corners */}
      <div className="w-full">
        <div className="flex items-center justify-between h-16 w-full">
          {/* App Name - flush left */}
          <div className="flex items-center min-w-0 ml-0 pl-0">
            <span
              className="truncate select-none"
              style={{
                fontWeight: 800,
                fontSize: '1.25rem',
                letterSpacing: '-0.02em',
                background: 'linear-gradient(90deg, #2563eb, #14b8a6)',
                WebkitBackgroundClip: 'text',
                backgroundClip: 'text',
                color: 'transparent',
                marginLeft: 0,
                paddingLeft: 8 // small breathing room so text isn't clipped on some devices
              }}
            >
              Helio
            </span>
          </div>

          {/* Logout button - flush right, pill-shaped like the reference image */}
          {user && onLogout && (
            <div className="mr-0 pr-0" style={{ paddingRight: 8 }}>
              <button
                onClick={onLogout}
                title="Logout"
                aria-label="Logout"
                className="uppercase tracking-wide"
                style={{
                  height: 36,
                  padding: '0 18px',
                  borderRadius: 9999,
                  background: 'linear-gradient(180deg, #93b0e6 0%, #7ea0e0 100%)',
                  color: '#ffffff',
                  fontWeight: 700,
                  fontSize: 14,
                  letterSpacing: '0.04em',
                  border: 'none',
                  boxShadow: '0 6px 0 rgba(97, 125, 179, 0.8), 0 10px 18px rgba(0,0,0,0.08)',
                  transform: 'translateZ(0)',
                  transition: 'transform 150ms ease, box-shadow 150ms ease'
                }}
                onMouseDown={(e) => {
                  e.currentTarget.style.transform = 'translateY(2px)';
                  e.currentTarget.style.boxShadow = '0 4px 0 rgba(97, 125, 179, 0.9), 0 8px 14px rgba(0,0,0,0.08)';
                }}
                onMouseUp={(e) => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 6px 0 rgba(97, 125, 179, 0.8), 0 10px 18px rgba(0,0,0,0.08)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 6px 0 rgba(97, 125, 179, 0.8), 0 10px 18px rgba(0,0,0,0.08)';
                }}
              >
                LOGOUT
              </button>
            </div>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
